// Agent 7: format output as standard envelope
// Mode: Run Once for All Items
// Reads from Call LLM's normalized response.
// Propagates structured error from Call LLM on failure.
// Returns flat scorer fields at top level for Application Recorder consumption.

const callLLM = $('Call LLM').first().json;

// Empty result shape returned on any failure (preserves downstream consumer contract)
const emptyResult = {
  overall_score: 0,
  recommendation: 'unknown',
  dimensions: {},
  strengths: [],
  gaps: [],
  rationale: '',
  strengths_text: '',
  gaps_text: '',
  score_rationale: ''
};

// Call LLM failed â€” propagate error
if (callLLM.success === false) {
  console.log(`[Agent 7] LLM call failed: ${callLLM.error?.category || 'unknown'} â€” ${callLLM.error?.message || 'no message'}`);
  return {
    json: {
      success: false,
      ...emptyResult,
      tokens: { input: callLLM.input_tokens || 0, output: callLLM.output_tokens || 0 },
      cached_input_tokens: callLLM.cached_input_tokens || 0,
      cache_write_tokens: callLLM.cache_write_tokens || 0,
      model_used: callLLM.model_used || 'unknown',
      provider_used: callLLM.provider_used || 'unknown',
      errors: [...(callLLM.errors || [])],
      error: callLLM.error || {
        category: 'unknown',
        type: 'unknown',
        message: 'Call LLM returned success: false with no error object',
        provider: callLLM.provider_used || 'unknown',
        model: callLLM.model_used || 'unknown'
      }
    }
  };
}

// Normal path: parse JSON from content
const response = $input.item.json;
const text = response.text || response.content || response.response || response.output_text || response.completion || '';

const parseErrors = [];
let parsed = null;
let repaired = false;

// Balance-repair for truncated JSON: appends missing closing braces/brackets.
// Walks the string tracking string-literal state (so braces inside strings are
// ignored) and escape sequences. Returns the input with any unclosed
// {/[ closed in correct nesting order, plus a closing quote if the string
// literal itself was left open. Conservative: only ever APPENDS closers.
const balanceRepair = (s) => {
  const stack = [];
  let inStr = false;
  let escaped = false;
  for (let i = 0; i < s.length; i++) {
    const c = s[i];
    if (inStr) {
      if (escaped) { escaped = false; }
      else if (c === '\\') { escaped = true; }
      else if (c === '"') { inStr = false; }
      continue;
    }
    if (c === '"') { inStr = true; }
    else if (c === '{' || c === '[') { stack.push(c); }
    else if (c === '}' || c === ']') { stack.pop(); }
  }
  let out = s;
  if (inStr) out += '"';                 // close a dangling string literal
  for (let i = stack.length - 1; i >= 0; i--) {
    out += stack[i] === '{' ? '}' : ']'; // close in reverse nesting order
  }
  return out;
};

if (!text) {
  parseErrors.push(`No text returned from Call LLM. Keys: ${Object.keys(response).join(', ')}`);
  console.log(`[Agent 7] ${parseErrors[parseErrors.length - 1]}`);
} else {
  const cleaned = String(text).replace(/^```(?:json)?\s*/i, '').replace(/\s*```\s*$/i, '').trim();
  try {
    parsed = JSON.parse(cleaned);
  } catch (err) {
    // Raw parse failed â€” attempt a single brace-balance repair before giving up.
    try {
      const fixed = balanceRepair(cleaned);
      if (fixed !== cleaned) {
        parsed = JSON.parse(fixed);
        repaired = true;
        const note = 'Recovered truncated JSON via brace-balance repair';
        parseErrors.push(note);   // soft note: success stays true, visible in analytics
        console.log(`[Agent 7] ${note}`);
      } else {
        throw err; // nothing to repair â€” original failure stands
      }
    } catch (err2) {
      const errMsg = err2 instanceof Error ? err2.message : String(err2);
      parseErrors.push(`Failed to parse JSON: ${errMsg}`);
      console.log(`[Agent 7] JSON parse failed (repair did not recover). Raw content (first 500 chars):\n${String(text).slice(0, 500)}`);
    }
  }

  if (parsed && typeof parsed.overall_score !== 'number') {
    parseErrors.push('Missing overall_score in response');
    console.log(`[Agent 7] ${parseErrors[parseErrors.length - 1]}`);
    parsed = null;
  }
}

const success = parsed !== null;
let error = null;
if (!success) {
  // Distinguish empty output vs parse failure vs schema violation.
  // A "repaired" note may precede the real failure â€” find the first HARD error.
  const hardErr = parseErrors.find(e =>
    e.startsWith('No text') || e.startsWith('Missing overall_score') || e.startsWith('Failed to parse')
  ) || '';
  let errorType = 'json_parse_failure';
  if (hardErr.startsWith('No text')) errorType = 'empty_output';
  else if (hardErr.startsWith('Missing overall_score')) errorType = 'schema_violation';

  error = {
    category: 'output_quality',
    type: errorType,
    message: parseErrors.join('; ') || 'Could not parse scorer output',
    provider: callLLM.provider_used || 'unknown',
    model: callLLM.model_used || 'unknown'
  };
}

const arr2text = (arr) => Array.isArray(arr) ? arr.join('; ') : '';

console.log(`[Agent 7] Score: ${parsed?.overall_score ?? 'parse failed'} (${parsed?.recommendation || 'n/a'})${repaired ? ' [repaired]' : ''}`);
console.log(`[Agent 7] Tokens: ${callLLM.input_tokens || 0}in + ${callLLM.output_tokens || 0}out + ${callLLM.cached_input_tokens || 0}cached + ${callLLM.cache_write_tokens || 0}cache_write`);

return {
  json: {
    success,
    overall_score: parsed?.overall_score ?? 0,
    recommendation: parsed?.recommendation || 'unknown',
    dimensions: parsed?.dimensions || {},
    strengths: parsed?.strengths || [],
    gaps: parsed?.gaps || [],
    rationale: parsed?.rationale || '',
    strengths_text: arr2text(parsed?.strengths),
    gaps_text: arr2text(parsed?.gaps),
    score_rationale: parsed?.rationale || '',
    tokens: { input: callLLM.input_tokens || 0, output: callLLM.output_tokens || 0 },
    cached_input_tokens: callLLM.cached_input_tokens || 0,
    cache_write_tokens: callLLM.cache_write_tokens || 0,
    model_used: callLLM.model_used || 'unknown',
    provider_used: callLLM.provider_used || 'unknown',
    errors: parseErrors,
    error
  }
};

// Set Inputs â€” Agent 7: Resume Scorer
const trigger = $input.item.json;

function strip(val) {
  if (val === null || val === undefined) return '';
  if (typeof val !== 'string') return val;
  let cleaned = val;
  while (cleaned.length > 0 && cleaned.charAt(0) === '=') {
    cleaned = cleaned.substring(1);
  }
  return cleaned;
}

const config = trigger.config || {};
const systemPrompt = strip(trigger.system_prompt);
const descriptionHtml = strip(trigger.description_html);
const resumeMarkdown = strip(trigger.resume_markdown);
const masterDoc = strip(trigger.master_doc);

const provider = strip(config.provider_resume_scorer);
if (!provider) {
  throw new Error('[Agent 7] config.provider_resume_scorer is required. Set it in your config sheet (anthropic | openai | gemini).');
}

const model = strip(config.model_resume_scorer);
if (!model) {
  throw new Error('[Agent 7] config.model_resume_scorer is required. Set it in your config sheet.');
}

const maxTokens = Number(config.max_tokens_resume_scorer);
if (!maxTokens || Number.isNaN(maxTokens)) {
  throw new Error('[Agent 7] config.max_tokens_resume_scorer is required and must be a number.');
}

console.log(`[Agent 7 Set Inputs] resume_markdown: ${resumeMarkdown.length} chars, master_doc: ${masterDoc.length} chars, provider: ${provider}, model: ${model}`);

return {
  json: {
    config,
    system_prompt: systemPrompt,
    description_html: descriptionHtml,
    resume_markdown: resumeMarkdown,
    master_doc: masterDoc,
    provider,
    model,
    max_tokens: maxTokens,
    profile_summary: config.profile_summary || '',
    target_titles: config.target_titles || '',
    domain_interests: config.domain_interests || ''
  }
};

// Build Prompt â€” Agent 7: Scorer
// Persona, dimension definitions, weighted formula, and recommendation thresholds
// live in system_prompt (Drive doc). This node injects the OUTPUT CONTRACT
// (JSON schema downstream depends on) and per-job inputs.
// Mode: Run Once for Each Item

const input = $input.item.json;
const descriptionHtml = input.description_html || '';
const resumeMarkdown = input.resume_markdown || '';
const profileSummary = input.profile_summary || '';
const targetTitles = input.target_titles || '';
const domainInterests = input.domain_interests || '';
const systemPromptFromDoc = input.system_prompt || '';

// Validation
if (!systemPromptFromDoc || systemPromptFromDoc.length < 100) {
  throw new Error(`[Agent 7] system_prompt missing or too short (${systemPromptFromDoc.length} chars). Check Prompt Loader output and orchestrator mapping.`);
}
if (!resumeMarkdown || resumeMarkdown.length < 30) {
  throw new Error(`[Agent 7] resume_markdown missing or too short (${resumeMarkdown.length} chars)`);
}
if (!descriptionHtml || descriptionHtml.length < 30) {
  throw new Error(`[Agent 7] description_html missing or too short (${descriptionHtml.length} chars)`);
}

console.log(`[Build Prompt] resume: ${resumeMarkdown.length} chars, JD: ${descriptionHtml.length} chars`);
console.log(`[Build Prompt] systemPromptFromDoc: ${systemPromptFromDoc.length} chars`);

// Pipeline-level output contract â€” JSON schema downstream Log Job Result depends on.
const OUTPUT_CONTRACT = `# OUTPUT CONTRACT (set by pipeline, do not override)

Output EXACTLY this JSON. No preamble, no markdown fences, no commentary outside JSON:

{
  "overall_score": <integer 0-100>,
  "recommendation": "strong_fit" or "fit" or "weak_fit" or "no_fit",
  "dimensions": {
    "technical_skills_match": <integer 0-10>,
    "requirements_coverage": <integer 0-10>,
    "level_match": <integer 0-10>,
    "domain_relevance": <integer 0-10>,
    "role_type_alignment": <integer 0-10>,
    "portfolio_strength": <integer 0-10>
  },
  "strengths": ["<strength 1>", "<strength 2>"],
  "gaps": ["<gap 1>", "<gap 2>"],
  "rationale": "<1-2 sentence summary>"
}`;

const system = systemPromptFromDoc + '\n\n' + OUTPUT_CONTRACT;

const userMessage = `Score how well this resume matches the target job.

# CANDIDATE POSITIONING CONTEXT
Profile summary anchor: ${profileSummary || '(derive from resume)'}
Target title categories: ${targetTitles || '(derive from resume)'}
Domain interests: ${domainInterests || '(derive from resume)'}

# FULL JOB DESCRIPTION
${descriptionHtml}

# CANDIDATE'S TAILORED RESUME
${resumeMarkdown}`;

console.log(`[Build Prompt] Final system: ${system.length} chars, user: ${userMessage.length} chars`);

return {
  json: {
    ...input,
    system,
    user_message: userMessage,
    prompt_chars: system.length + userMessage.length
  }
};

// Build Cascade Output â€” Agent 7
// Mode: Run Once for All Items
// Fires when upstream agent (1) failed. Passes upstream error through unchanged.
// Flat output shape matches Agent 7 Format Output for Application Recorder compatibility.

const trigger = $('Trigger').first().json;
const upstreamError = trigger.cascade_error || {};

console.log(`[Agent 7] CASCADE â€” skipping due to ${upstreamError.source_agent || 'upstream'}: ${upstreamError.category || 'unknown'}`);

return {
  json: {
    success: false,
    cascaded: true,
    overall_score: 0,
    recommendation: 'unknown',
    dimensions: {},
    strengths: [],
    gaps: [],
    rationale: '',
    strengths_text: '',
    gaps_text: '',
    score_rationale: '',
    tokens: { input: 0, output: 0 },
    cached_input_tokens: 0,
    cache_write_tokens: 0,
    model_used: 'skipped',
    provider_used: 'skipped',
    errors: [`cascade: ${upstreamError.source_agent || 'upstream'}:${upstreamError.category || 'unknown'}`],
    error: upstreamError
  }
};
